(window.webpackJsonp=window.webpackJsonp||[]).push([[62],{333:function(n,e,t){"use strict";t.r(e);var i=t(10),a=Object(i.a)({},(function(){var n=this,e=n._self._c;return e("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[e("h1",{attrs:{id:"financial-system"}},[e("a",{staticClass:"header-anchor",attrs:{href:"#financial-system"}},[n._v("#")]),n._v(" Financial System")]),n._v(" "),e("h2",{attrs:{id:"financial-system-2"}},[e("a",{staticClass:"header-anchor",attrs:{href:"#financial-system-2"}},[n._v("#")]),n._v(" Financial System")]),n._v(" "),e("div",{staticClass:"custom-block warning"},[e("p",{staticClass:"custom-block-title"},[n._v("Financial System")]),n._v(" "),e("p",[n._v("The "),e("strong",[n._v("financial system")]),n._v(" is a concept that encompasses all "),e("strong",[n._v("financial infrastructures")]),n._v(" such as "),e("strong",[n._v("financial markets")]),n._v(" and "),e("strong",[n._v("financial institutions")]),n._v(", laws and practices that form, operate, and function smoothly.")])]),n._v(" "),e("p",[n._v("This page is based on the contents posted on the Bank of Korea website.")]),n._v(" "),e("ul",[e("li",[e("a",{attrs:{href:"http://www.bok.or.kr/eng/main/contents.do?menuNo=400098",target:"_blank",rel:"noopener noreferrer"}},[n._v("Bank of Korea, Financial System"),e("OutboundLink")],1)]),n._v(" "),e("li",[e("a",{attrs:{href:"http://www.bok.or.kr/eng/bbs/E0000743/view.do?nttId=10050214&menuNo=400226&pageIndex=1",target:"_blank",rel:"noopener noreferrer"}},[n._v("Financial System in Korea, BOK"),e("OutboundLink")],1)])]),n._v(" "),e("h2",{attrs:{id:"financial-markets"}},[e("a",{staticClass:"header-anchor",attrs:{href:"#financial-markets"}},[n._v("#")]),n._v(" Financial Markets")]),n._v(" "),e("div",{staticClass:"custom-block warning"},[e("p",{staticClass:"custom-block-title"},[n._v("Financial Markets")]),n._v(" "),e("p",[e("strong",[n._v("Financial markets")]),n._v(" are organized venues where economic players may raise and operate funds through transactions in "),e("strong",[n._v("financial instruments")]),n._v(". The financial markets are divided into the direct and the indirect financing markets, depending upon whether or not the transactions are conducted through financial intermediaries.")]),n._v(" "),e("p",[n._v("The indirect financing markets are exchanges where funds are brokered through deposits and loans; the deposits and loans market is a good example. Financial transactions are carried out by banks, non-bank depository institutions, collective investment business entities, trust business entities, etc., that provide funds by lending money or by buying direct securities with funds raised through indirect securities such as certificates of deposit and beneficiary certificates.")]),n._v(" "),e("p",[n._v("Financial transactions into direct financing markets are undertaken as the fund providers purchase direct or primary securities issued by the end consumers of the funds, such as financial debentures or corporate bonds. Accordingly, the direct financing markets, which do not depend on financial intermediaries, play more active roles and are more diversified than the indirect financing markets.")]),n._v(" "),e("p",[n._v("In accordance with the maturities of the financial instruments involved, the direct financing markets are generally divided into the money markets and the capital markets. Additionally, they can be divided into the foreign exchange markets and the financial derivatives markets, in consideration of the features ofthe financial instruments concerned.")])]),n._v(" "),e("h2",{attrs:{id:"financial-institutions"}},[e("a",{staticClass:"header-anchor",attrs:{href:"#financial-institutions"}},[n._v("#")]),n._v(" Financial Institutions")]),n._v(" "),e("div",{staticClass:"custom-block warning"},[e("p",{staticClass:"custom-block-title"},[n._v("Financial Institutions")]),n._v(" "),e("p",[e("strong",[n._v("Financial institutions")]),n._v(" serve mainly as intermediaries for savings and investment between savers and borrowers, and are commonly divided into six categories: "),e("strong",[n._v("banks, non-bank depository institutions, financial investment business entities, insurance companies, other financial institutions")]),n._v(", and financial auxiliary institutions.")]),n._v(" "),e("p",[e("strong",[n._v("Banks")]),e("br"),n._v("\nTo elaborate on the financial institutions making up each category under this classification, banks are divided into commercial banks and specialized banks. Commercial banks consist of nationwide and local banks and branches of foreign banks. Special banks are financial institutions established under a special act rather than the Banking Act, and their main enterprises are banking businesses. Specialized banks include the Korea Development Bank, the Export-Import Bank of Korea, the Industrial Bank of Korea, Nonghyup Bank, Suhyup Bank, and others.")]),n._v(" "),e("p",[e("strong",[n._v("Non-bank Depository Institutions")]),e("br"),n._v("\nNon-bank depository institutions mainly concern themselves with taking deposits and lending, similar to banks, but are established for more limited purposes and fall under distinct regulations concerning their raising and management of funds. That is, the scope of their business activities is narrower than that of banks, payment and settlement services are either non-existent or provided in a limited manner, and the focuses of their businesses are restricted in advance in accordance with each financial institution's unique features. Non-bankdepository institutions comprise mutual savings banks, credit cooperatives including credit unions, community credit cooperatives and mutual banking entities, merchant banks and the postal savings.")]),n._v(" "),e("p",[e("strong",[n._v("Financial Investment Business Entities")]),e("br"),n._v("\nFinancial investment business entities include all financial institutions that primarily conduct the business of trading marketable securities in the direct financing markets. These consist of investment traders and brokers (securities and futures companies), collective investment business entities, investment advisory and discretionary investment business entities, and trust business entities.")]),n._v(" "),e("p",[e("strong",[n._v("Insurance Companies")]),n._v("\nInsurance companies are those institutions that underwrite and operate insurance against death, disease, old age, or a variety of accidents including fires. In consideration of the features of the institutions and their businesses, they are categorized into entities providing life insurance, non-life insurance, postal insurance, mutual aid, and others. Non-life insurance companies consist of property and casualty insurance companies, reinsurance companies, and guarantee insurance companies.")]),n._v(" "),e("p",[e("strong",[n._v("Other Financial Institutions")]),e("br"),n._v("\nOther financial institutions include institutions mainly operating financial businesses that are difficult to classify among the financial institutions in the four aforementioned categories. They consist of financial holding companies, creditspecialized financial companies (leasing, credit card, installment financing, and new technology venture capital companies), venture capital companies (small and medium-sized enterprise establishment investment companies), securities finance companies, public financial institutions, and others.")]),n._v(" "),e("p",[e("strong",[n._v("Financial Auxiliary Institutions")]),e("br"),n._v("\nFinancial auxiliary institutions are those institutions that, rather than directly taking part in financial transactions, mainly provide the conditions necessary for smooth operation of the financial system. They span institutions carrying out businesses related to financial infrastructure such as the Financial Supervisory Service, the Korea Deposit Insurance Corporation, the Korea Financial Telecommunications and Clearings Institute, the Korea Securities Depository, the Korea Exchange, credit guarantee institutions including the Korea Credit Guarantee Fund and the Korea Technology Finance Corporation, credit information companies, financial brokerage companies, and others.")])]),n._v(" "),e("h2",{attrs:{id:"financial-infrastructure"}},[e("a",{staticClass:"header-anchor",attrs:{href:"#financial-infrastructure"}},[n._v("#")]),n._v(" Financial Infrastructure")]),n._v(" "),e("div",{staticClass:"custom-block warning"},[e("p",{staticClass:"custom-block-title"},[n._v("Financial Infrastructure")]),n._v(" "),e("p",[e("strong",[n._v("Financial infrastructure")]),n._v(" indicates the legal system or institutions that support and oversee the financial institutions and markets in order to ensure smooth financial transactions. It comprises the "),e("strong",[n._v("central banking system, the payment and settlement system, the financial supervisory system, the deposit insurance system, and more")]),n._v(".")]),n._v(" "),e("p",[e("strong",[n._v("Central Bank")]),e("br"),n._v("\nThe central banking system includes the central bank, its organization, decisionmaking system and sphere of business. As the lender of last resort with the right to issue banknotes and coins, the central bank performs the function of determining policy rate, imposing reserve requirements on the deposits of banks and, if necessary, supplies financial institutions with needed funds. These functions contribute to price stabilization, as well as stabilization of the financial system. The Bank of Korea, founded on June 12, 1950, serves as Korea's central bank.")]),n._v(" "),e("p",[e("strong",[n._v("Payment and Settlement System")]),e("br"),n._v("\nThe payment and settlement system performs the function of settling credits and debts established through real economic and financial transactions. It consists of means of payment, participant institutions and the settlement system. Means of payment include cash and non-cash instruments such as bills, checks and credit cards. The participant institutions comprise those financial institutions that provide non-cash instruments of payment, such as banks, the post office and credit card companies; clearing houses, which offset debts between financial institutions and include the Korea Financial Telecommunications and Clearings Institute; and the Bank of Korea, which finalizes payment and settlement by transferring funds between the current accounts of financial institutions. The settlement system is divided into the net and the gross settlement systems, depending upon the settlement method, as well as the retail payment system and the large value payment system, depending upon the features of the transactions concerned. In general, owing to the natures of the transactions concerned, the retail payment system is operated by the net settlement system and the large value payment system is managed according to the gross settlement system. In Korea, the gross settlement system for large value payments is conducted through BOK-Wire+, operated by the Bank of Korea. The net settlement system for retail payment is conducted through the bill clearing system, the GIRO system, the bank information network and others, managed by the Korea Financial Telecommunications and Clearings Institute.")]),n._v(" "),e("p",[e("strong",[n._v("Financial Supervisory System")]),e("br"),n._v("\nThe financial supervisory system aims to protect the properties of finance customers and promote financial transactions by ensuring that institutions conduct financial intermediation fairly, as well as by fostering sound management. For this purpose, financial supervisory institutions perform the function of approving the establishment of financial institutions, drafting regulations to be followed by financial institutions in conducting their business, and overseeing regulatory compliance. Korea applies an integrated financial supervisory system, in which the Financial Services Commission (FSC) and the Financial Supervisory Service (FSS) supervise nearly all financial institutions. The FSC deliberates on and determines important matters concerning financial supervision, including financial supervisory policies and the licensing of financial institutions, while the FSS implements the decisions of the FSC and examines and supervises financial institutions. In addition, the Bank of Korea and the Korea Deposit Insurance Corporation partially serve supervisory roles with limited functions of financial oversight, such as requesting inspections and conducting joint examinations with the FSS.")]),n._v(" "),e("p",[e("strong",[n._v("Deposit Insurance System")]),e("br"),n._v("\nThe deposit insurance system is a type of insurance system through which, when a financial institution is unable to pay the principal or interest it owes due to unsuccessful managements, a deposit insurance institution remits a portion or all of the principal and interest in the place of that financial institution. The deposit insurance system serves as a financial safety net, protecting small-scale depositors from the reckless management of financial institutions and preventing bank runs. The deposit insurance system in Korea was organized in 1996 with establishment of the Korea Deposit Insurance Corporation. Currently, bank deposits and selected financial instruments from securities and insurance companies are protected by the system. Thrift institutions such as credit unions, community credit cooperatives, agricultural cooperatives, fisheries cooperatives and forestry cooperatives support proprietary deposit protection systems, as they aim at mutual aid among cooperative members. Postal savings and insurance are not covered by the Korea Deposit Insurance Corporation, because payment in these systems is guaranteed by the government in accordance with the related legislation.")])])])}),[],!1,null,null,null);e.default=a.exports}}]);